#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
vector<int> adj[MAXN];
int depth[MAXN], sz[MAXN], height[MAXN];

// Pre-order: depth flows DOWN from parent
void dfs_depth(int u, int par, int d) {
    depth[u] = d;
    for (int v : adj[u])
        if (v != par)
            dfs_depth(v, u, d + 1);
}

// Post-order: size and height computed BOTTOM-UP from leaves
void dfs_size_height(int u, int par) {
    sz[u] = 1;
    height[u] = 0;
    for (int v : adj[u]) {
        if (v != par) {
            dfs_size_height(v, u);
            sz[u] += sz[v];
            height[u] = max(height[u], height[v] + 1);
        }
    }
}

int main() {
    int n; cin >> n;
    for (int i = 0; i < n - 1; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    dfs_depth(1, 0, 0);
    dfs_size_height(1, 0);
    // depth[v] = distance from root to v
    // sz[v]    = number of nodes in subtree rooted at v
    // height[v]= length of longest path from v down to a leaf
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
vector<int> adj[MAXN];
int ans_diam = 0;

// DFS approach: O(n)
int dfs_diam(int u, int par) {
    int best1 = 0, best2 = 0; // two longest depths among children
    for (int v : adj[u]) {
        if (v == par) continue;
        int h = dfs_diam(v, u) + 1;
        if (h > best1) { best2 = best1; best1 = h; }
        else if (h > best2) best2 = h;
    }
    ans_diam = max(ans_diam, best1 + best2);
    return best1;
}

// Two-BFS approach: O(n)
pair<int,int> bfs_farthest(int src, int n) {
    vector<int> dist(n + 1, -1);
    queue<int> q;
    q.push(src); dist[src] = 0;
    int farthest = src;
    while (!q.empty()) {
        int u = q.front(); q.pop();
        if (dist[u] > dist[farthest]) farthest = u;
        for (int v : adj[u])
            if (dist[v] == -1) { dist[v] = dist[u] + 1; q.push(v); }
    }
    return {farthest, dist[farthest]};
}

int diameter_bfs(int n) {
    auto [u, d1] = bfs_farthest(1, n);
    auto [v, d2] = bfs_farthest(u, n);
    return d2;
}

int main() {
    int n; cin >> n;
    for (int i = 0; i < n - 1; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    dfs_diam(1, 0);
    cout << ans_diam << "\n";       // DFS diameter
    cout << diameter_bfs(n) << "\n"; // BFS diameter
}

#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
vector<int> adj[MAXN];
int tin[MAXN], tout[MAXN], order[MAXN];
int timer_val = 0;

void dfs_euler(int u, int par) {
    tin[u] = timer_val;
    order[timer_val] = u; // flattened array position
    timer_val++;
    for (int v : adj[u])
        if (v != par) dfs_euler(v, u);
    tout[u] = timer_val - 1; // inclusive end
}

bool isAncestor(int u, int v) {
    return tin[u] <= tin[v] && tout[v] <= tout[u];
}

// After euler tour, subtree of u = order[tin[u]..tout[u]]
// Range query on subtree of u → query range [tin[u], tout[u]] on order[]

int main() {
    int n; cin >> n;
    for (int i = 0; i < n - 1; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    dfs_euler(1, 0);
    // Example: is node 3 in subtree of node 1?
    cout << isAncestor(1, 3) << "\n";
}

#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
const int LOG = 17; // 2^17 > 10^5
vector<int> adj[MAXN];
int up[MAXN][LOG]; // up[v][j] = 2^j-th ancestor of v
int depth[MAXN];

void dfs(int u, int par, int d) {
    depth[u] = d;
    up[u][0] = par;
    for (int j = 1; j < LOG; j++)
        up[u][j] = up[up[u][j-1]][j-1];
    for (int v : adj[u])
        if (v != par) dfs(v, u, d + 1);
}

int lca(int u, int v) {
    if (depth[u] < depth[v]) swap(u, v);
    int diff = depth[u] - depth[v];
    // Bring u up to same depth as v
    for (int j = 0; j < LOG; j++)
        if ((diff >> j) & 1) u = up[u][j];
    if (u == v) return u;
    // Lift both until their parents are the same
    for (int j = LOG - 1; j >= 0; j--)
        if (up[u][j] != up[v][j]) {
            u = up[u][j];
            v = up[v][j];
        }
    return up[u][0];
}

int dist(int u, int v) {
    return depth[u] + depth[v] - 2 * depth[lca(u, v)];
}

int main() {
    int n, q; cin >> n >> q;
    for (int i = 0; i < n - 1; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    dfs(1, 1, 0); // root=1, parent[root]=root avoids out-of-bounds
    while (q--) {
        int u, v; cin >> u >> v;
        cout << lca(u, v) << " " << dist(u, v) << "\n";
    }
}

#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node *left, *right;
    Node(int v) : val(v), left(nullptr), right(nullptr) {}
};

Node* insert(Node* root, int val) {
    if (!root) return new Node(val);
    if (val < root->val) root->left  = insert(root->left,  val);
    else if (val > root->val) root->right = insert(root->right, val);
    // duplicate: do nothing
    return root;
}

bool search(Node* root, int val) {
    if (!root) return false;
    if (val == root->val) return true;
    if (val < root->val) return search(root->left,  val);
    else                 return search(root->right, val);
}

// In-order traversal → sorted order
void inorder(Node* root, vector<int>& out) {
    if (!root) return;
    inorder(root->left,  out);
    out.push_back(root->val);
    inorder(root->right, out);
}

// Find min node in a subtree (leftmost)
Node* findMin(Node* root) {
    while (root->left) root = root->left;
    return root;
}

// Delete a node
Node* deleteNode(Node* root, int val) {
    if (!root) return nullptr;
    if (val < root->val)      root->left  = deleteNode(root->left,  val);
    else if (val > root->val) root->right = deleteNode(root->right, val);
    else { // found it
        if (!root->left)  return root->right;
        if (!root->right) return root->left;
        // Two children: replace with in-order successor
        Node* succ = findMin(root->right);
        root->val = succ->val;
        root->right = deleteNode(root->right, succ->val);
    }
    return root;
}

int main() {
    Node* root = nullptr;
    for (int x : {5, 3, 7, 1, 4, 6, 8})
        root = insert(root, x);
    vector<int> sorted;
    inorder(root, sorted);
    for (int x : sorted) cout << x << " "; cout << "\n"; // 1 2 3 4 5 6 7 8
    cout << search(root, 4) << "\n"; // 1
    root = deleteNode(root, 5);
    sorted.clear(); inorder(root, sorted);
    for (int x : sorted) cout << x << " "; cout << "\n"; // 1 3 4 6 7 8
}

#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val; Node *left, *right;
    Node(int v) : val(v), left(nullptr), right(nullptr) {}
};

bool isValidBST(Node* root, long long lo, long long hi) {
    if (!root) return true;
    if (root->val <= lo || root->val >= hi) return false;
    return isValidBST(root->left,  lo,       root->val)
        && isValidBST(root->right, root->val, hi);
}

// Also: k-th smallest in BST via inorder (O(k) time)
int kthSmallest(Node* root, int& k) {
    if (!root) return -1;
    int left = kthSmallest(root->left, k);
    if (k == 0) return left;
    if (--k == 0) return root->val;
    return kthSmallest(root->right, k);
}

int main() {
    //      5
    //     / \
    //    3   7
    //   / \
    //  1   4
    Node* root = new Node(5);
    root->left = new Node(3); root->right = new Node(7);
    root->left->left = new Node(1); root->left->right = new Node(4);
    cout << isValidBST(root, LLONG_MIN, LLONG_MAX) << "\n"; // 1 (valid)

    // Invalid: right child of 3 is 6 (> 5, violates subtree constraint)
    root->left->right->val = 6;
    cout << isValidBST(root, LLONG_MIN, LLONG_MAX) << "\n"; // 0 (invalid)
}

