#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
vector<pair<int,int>> adj[MAXN]; // {neighbor, weight}
long long ans = 0;

long long dfs(int u, int par) {
    long long best1 = 0, best2 = 0;
    for (auto [v, w] : adj[u]) {
        if (v == par) continue;
        long long depth = dfs(v, u) + w;
        if (depth > best1)       { best2 = best1; best1 = depth; }
        else if (depth > best2)    best2 = depth;
    }
    ans = max(ans, best1 + best2);
    return best1;
}

int main() {
    int n; cin >> n;
    for (int i = 0; i < n - 1; i++) {
        int u, v, w; cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }
    dfs(1, 0);
    cout << ans << "\n";
}

