#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
vector<int> adj[MAXN];
int val[MAXN], tin[MAXN], tout[MAXN];
int flat[MAXN]; // flat[tin[u]] = val[u]
int timer_cnt = 0;

void dfs(int u, int par) {
    tin[u] = timer_cnt;
    flat[timer_cnt++] = val[u];
    for (int v : adj[u]) if (v != par) dfs(v, u);
    tout[u] = timer_cnt - 1;
}

// Brute force per query: O(n) — replace with persistent seg tree for O(log^2 n)
int query(int u, int L, int R) {
    int cnt = 0;
    for (int i = tin[u]; i <= tout[u]; i++)
        if (flat[i] >= L && flat[i] <= R) cnt++;
    return cnt;
}

int main() {
    int n, q; cin >> n >> q;
    for (int i = 1; i <= n; i++) cin >> val[i];
    for (int i = 0; i < n - 1; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v); adj[v].push_back(u);
    }
    dfs(1, 0);
    while (q--) {
        int u, L, R; cin >> u >> L >> R;
        cout << query(u, L, R) << "\n";
    }
}
